import { useState, useEffect } from "react";

const StudyRoom = ({ task }) => {
    const [seconds, setSeconds] = useState(0);
    const [showQuiz, setShowQuiz] = useState(false);
    const [lastMove, setLastMove] = useState(Date.now());

    useEffect(() => {
        // 1. Mouse Movement Tracker
        const trackMove = () => setLastMove(Date.now());
        window.addEventListener("mousemove", trackMove);

        // 2. Main Timer (5-minute interval for AI Quiz)
        const timer = setInterval(() => {
            setSeconds(prev => {
                if (prev > 0 && prev % 300 === 0) { // 300 seconds = 5 mins
                    setShowQuiz(true);
                }
                return prev + 1;
            });

            // Check if user is idle for more than 2 minutes
            if (Date.now() - lastMove > 120000) {
                console.log("User is idle! Redirecting or lowering Pulse score...");
            }
        }, 1000);

        return () => {
            window.removeEventListener("mousemove", trackMove);
            clearInterval(timer);
        };
    }, [lastMove]);

    return (
        <div className="study-session">
            <h2>Studying: {task.title}</h2>
            <p>Focus Time: {Math.floor(seconds / 60)} mins</p>

            {showQuiz && (
                <div className="modal bg-white p-5 border shadow-lg">
                    <h3>AI Verification: Answer to Continue</h3>
                    <p>What is the main concept of {task.title}?</p>
                    <input type="text" className="border p-2 w-full" />
                    <button onClick={() => setShowQuiz(false)} className="mt-2 bg-black text-white p-2">
                        Submit & Continue
                    </button>
                </div>
            )}
        </div>
    );
};

export default StudyRoom
